  const n01 = g01[0]! * xf + g01[1]! * (yf - 1);
  const n11 = g11[0]! * (xf - 1) + g11[1]! * (yf - 1);

  const u = fade(xf);
  const v = fade(yf);

  return (
    n00 * (1 - u) * (1 - v) +
    n10 * u * (1 - v) +
    n01 * (1 - u) * v +
    n11 * u * v
  );
}

const NOISE_SCALE = 0.003;
const CURVE_COUNT = 800;
const STEP_LENGTH = 2;
const STEPS_PER_CURVE = 150;
const BASE_ANGLE = Math.PI * 0.15;

function draw(canvas: HTMLCanvasElement) {
  const ctx = canvas.getContext("2d")!;
  const dpr = window.devicePixelRatio || 1;
  const rect = canvas.getBoundingClientRect();

  canvas.width = rect.width * dpr;
  canvas.height = rect.height * dpr;
  ctx.setTransform(dpr, 0, 0, dpr, 0, 0);

  const w = rect.width;
  const h = rect.height;

  ctx.fillStyle = "#000";
  ctx.fillRect(0, 0, w, h);

  initNoise(42);

  const rng = { s: 12345 };
  function seededRandom() {
    rng.s = (rng.s * 16807) % 2147483647;
    return (rng.s - 1) / 2147483646;
  }

  for (let i = 0; i < CURVE_COUNT; i++) {
    let x = seededRandom() * w;
    let y = seededRandom() * h;

    ctx.beginPath();
    ctx.moveTo(x, y);

    for (let s = 0; s < STEPS_PER_CURVE; s++) {
      const n = noise2d(x * NOISE_SCALE, y * NOISE_SCALE);
      const angle = n * Math.PI * 2.5 + BASE_ANGLE;

      x += Math.cos(angle) * STEP_LENGTH;
      y += Math.sin(angle) * STEP_LENGTH;

      ctx.lineTo(x, y);

      if (x < -10 || x > w + 10 || y < -10 || y > h + 10) break;
    }

    ctx.strokeStyle = "rgba(200, 210, 180, 0.12)";
    ctx.lineWidth = 0.8;
    ctx.stroke();
  }
}

export function FlowField() {
  const canvasRef = useRef<HTMLCanvasElement>(null);

  useEffect(() => {
    const canvas = canvasRef.current!;
    draw(canvas);

    const onResize = () => draw(canvas);
    window.addEventListener("resize", onResize);
    return () => window.removeEventListener("resize", onResize);
  }, []);

  return (
    <canvas
      ref={canvasRef}
      style={{ width: "100%", height: "100%", display: "block" }}
